import React, { useState, useEffect } from 'react'

import './category.scss'


export default function Category({ data = [], clickHandle = () => {}, activeCate = [] }) {
  const [active, setActive] = useState(activeCate.length ? activeCate : ['All'])
  
  const onClick = (name) => {
    const key = active.indexOf(name)
    let data = [...active]

    if (key !== -1) {
      data.splice(key, 1)
    } else {
      data.push(name)
    }

    if (name === 'All' || data.length === 0) {
      data = ['All']
    }

    if (data.length > 1) {
      let key2 = data.indexOf('All')

      if (key2 !== -1) {
        data.splice(key2, 1)
      }
    }

    setActive(data)
  }

  useEffect(() => {
    clickHandle(active)
  }, [active])


  return (
    <div className="categoryArea">
      {data.map((v, i) => (
        <div 
          key={i} 
          className={`item ${active.includes(v) ? 'active' : ''}`} 
          onClick={() => onClick(v)}
        >
          {v}
        </div>
      ))}
    </div>
  )
}